import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is the Pythagorean theorem?", a: "The Pythagorean theorem says that in a right triangle, a^2 + b^2 = c^2 where c is the hypotenuse and a and b are the legs." },
  { q: "How do you find the hypotenuse?", a: "Square both legs, add them, then take the square root: c = sqrt(a^2 + b^2)." },
  { q: "How do you find a missing leg of a right triangle?", a: "Square the hypotenuse, subtract the known leg squared, then take the square root: a = sqrt(c^2 - b^2)." },
  { q: "What are Pythagorean triples?", a: "Pythagorean triples are whole-number side lengths that satisfy a^2 + b^2 = c^2 such as 3, 4, 5 or 5, 12, 13." },
  { q: "How is the Pythagorean theorem used in real life?", a: "It is used in construction, navigation, screen measurements, diagonal distances, surveying, and any situation involving right-triangle geometry." },
];

type SolveFor = "hypotenuse" | "legA" | "legB";
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "Invalid";
const deg = (rad: number) => rad * 180 / Math.PI;

export default function PythagoreanTheoremCalculator() {
  const [solveFor, setSolveFor] = useState<SolveFor>("hypotenuse");
  const [a, setA] = useState(3);
  const [b, setB] = useState(4);
  const [c, setC] = useState(5);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    let legA = a, legB = b, hyp = c, step = "";
    if (solveFor === "hypotenuse") { hyp = Math.sqrt(a * a + b * b); step = `c = sqrt(${a}^2 + ${b}^2) = sqrt(${a * a + b * b}) = ${fmt(hyp)}.`; }
    if (solveFor === "legA") { legA = Math.sqrt(Math.max(0, c * c - b * b)); step = `a = sqrt(${c}^2 - ${b}^2) = sqrt(${c * c - b * b}) = ${fmt(legA)}.`; }
    if (solveFor === "legB") { legB = Math.sqrt(Math.max(0, c * c - a * a)); step = `b = sqrt(${c}^2 - ${a}^2) = sqrt(${c * c - a * a}) = ${fmt(legB)}.`; }
    const angleA = deg(Math.asin(legA / hyp));
    const angleB = 90 - angleA;
    const triple = Number.isInteger(legA) && Number.isInteger(legB) && Number.isInteger(hyp) ? "Pythagorean triple" : "Right triangle";
    return { legA, legB, hyp, angleA, angleB, triple, step };
  }, [solveFor, a, b, c]);

  return (
    <>
      <SEOHead title="Free Pythagorean Theorem Calculator Online - Solve Any Right Triangle Instantly | CalcHive" description="Free online Pythagorean theorem calculator. Solve for any side of a right triangle using a^2 + b^2 = c^2 with step by step solution instantly. 100% free for students, no signup required." canonical="/pythagorean-theorem-calculator" keywords="free pythagorean theorem calculator, hypotenuse calculator free online, right triangle calculator free, a squared plus b squared calculator free, pythagorean theorem solver free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Pythagorean Theorem Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free pythagorean theorem calculator to solve any side of a right triangle with a^2 + b^2 = c^2.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label htmlFor="solve-for" className="text-sm font-semibold text-foreground block mb-2">Solve for</label><select id="solve-for" value={solveFor} onChange={(event) => setSolveFor(event.target.value as SolveFor)} className={inputClass}><option value="hypotenuse">Hypotenuse c</option><option value="legA">Leg a</option><option value="legB">Leg b</option></select></div>
            {solveFor !== "legA" && <div><label htmlFor="leg-a" className="text-sm font-semibold text-foreground block mb-2">Leg a</label><input id="leg-a" type="number" min="0" inputMode="decimal" value={a} onChange={(event) => setA(Number(event.target.value))} className={inputClass} /></div>}
            {solveFor !== "legB" && <div><label htmlFor="leg-b" className="text-sm font-semibold text-foreground block mb-2">Leg b</label><input id="leg-b" type="number" min="0" inputMode="decimal" value={b} onChange={(event) => setB(Number(event.target.value))} className={inputClass} /></div>}
            {solveFor !== "hypotenuse" && <div><label htmlFor="hypotenuse" className="text-sm font-semibold text-foreground block mb-2">Hypotenuse c</label><input id="hypotenuse" type="number" min="0" inputMode="decimal" value={c} onChange={(event) => setC(Number(event.target.value))} className={inputClass} /></div>}
          </div>
          <motion.div key={`${solveFor}-${a}-${b}-${c}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.triple}</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-pythagorean">{solveFor === "hypotenuse" ? fmt(result.hyp) : solveFor === "legA" ? fmt(result.legA) : fmt(result.legB)}</p></div>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mt-4">{[["a", result.legA], ["b", result.legB], ["c", result.hyp], ["Angles", `${fmt(result.angleA)} deg / ${fmt(result.angleB)} deg / 90 deg`]].map(([label, val]) => <div key={label as string} className="bg-accent/60 border border-border rounded-xl p-3 text-center"><p className="text-xs text-muted-foreground font-medium">{label}</p><p className="text-sm font-extrabold text-foreground">{typeof val === "number" ? fmt(val) : val}</p></div>)}</div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground font-mono" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Use the Pythagorean Theorem for Free</h2><p className="text-muted-foreground leading-relaxed">Choose the missing side, enter the known sides, and this pythagorean theorem solver free tool applies a^2 + b^2 = c^2.</p><h2 className="text-2xl font-bold text-foreground">How to Solve for Any Side of a Right Triangle</h2><p className="text-muted-foreground leading-relaxed">Use c = sqrt(a^2 + b^2) for the hypotenuse, or rearrange the formula to solve for a missing leg.</p><h2 className="text-2xl font-bold text-foreground">Free Right Triangle Hypotenuse Calculator for Students</h2><p className="text-muted-foreground leading-relaxed">Use this hypotenuse calculator free online for geometry homework, right-triangle checks, and distance problems.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/pythagorean-theorem-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


